const product = $input.first().json.product;
const nutriments = product.nutriments || {};

// Récupération des valeurs //
// --- Valeurs nutritionnelles pour 100g --- //
const energy   = nutriments['energy-kj_100g'] || 0;
const fat      = nutriments['fat_100g'] || 0;
const sat_fat  = nutriments['saturated-fat_100g'] || 0;
const sugar    = nutriments['sugars_100g'] || 0;
const salt     = nutriments['salt_100g'] || 0;
const fiber    = nutriments['fiber_100g'] || 0;
const proteins = nutriments['proteins_100g'] || 0;
const fruits   = nutriments['fruits-vegetables-nuts-estimate-from-ingredients_100g'] || 0;

// --- Points négatifs (N) : plus c'est élevé, plus c'est mauvais --- //
const n_energy  = energy > 3350 ? 10 : energy > 3015 ? 9 : energy > 2680 ? 8 : energy > 2345 ? 7 : energy > 2010 ? 6 : energy > 1675 ? 5 : energy > 1340 ? 4 : energy > 1005 ? 3 : energy > 670 ? 2 : energy > 335 ? 1 : 0;
const n_sugar   = sugar > 45 ? 10 : sugar > 36 ? 9 : sugar > 27 ? 7 : sugar > 18 ? 6 : sugar > 9 ? 3 : sugar > 4.5 ? 1 : 0;
const n_sat_fat = sat_fat > 10 ? 10 : sat_fat > 8 ? 9 : sat_fat > 6 ? 7 : sat_fat > 4 ? 6 : sat_fat > 2 ? 3 : sat_fat > 1 ? 1 : 0;
const n_salt    = salt > 2.3 ? 10 : salt > 1.5 ? 9 : salt > 0.9 ? 7 : salt > 0.6 ? 6 : salt > 0.3 ? 3 : salt > 0.15 ? 1 : 0;
const N = n_energy + n_sugar + n_sat_fat + n_salt;

// --- Points positifs (P) : réduisent le score final --- //
const p_fiber = fiber > 4.7 ? 5 : fiber > 3.7 ? 4 : fiber > 2.8 ? 3 : fiber > 1.9 ? 2 : fiber > 0.9 ? 1 : 0;
const p_proteins = proteins > 8 ? 5 : proteins > 6.4 ? 4 : proteins > 4.8 ? 3 : proteins > 3.2 ? 2 : proteins > 1.6 ? 1 : 0;
const p_fruits = fruits > 80 ? 5 : fruits > 60 ? 2 : fruits > 40 ? 1 : 0;

// Règle FSA : si produit très mauvais et peu de fruits, les protéines ne compensent pas //
const P = (N >= 11 && p_fruits <= 1) ? p_fiber + p_fruits : p_fiber + p_proteins + p_fruits;

// --- Score final = mauvais - bons --- //
const score = N - P;

// --- Attribution de la lettre selon le score --- //
const grade = score <= -1 ? 'A' : score <= 2 ? 'B' : score <= 10 ? 'C' : score <= 18 ? 'D' : 'E';

// --- Résultat retourné à l'app mobile --- //
return [{
  json: {
    product_name:        product.product_name || 'Inconnu',
    brands:              product.brands || 'Inconnu',
    nutriscore_predit:   grade,
    nutriscore_officiel: product.nutrition_grades || 'Non disponible',
    score_numerique:     score,
    fat:       fat,
    sugar:     sugar,
    salt:      salt,
    proteins:  proteins,
    fiber:     fiber,
    energy_kj: energy,
    sat_fat:   sat_fat,
    fruits_veg:fruits,
    image_url: product.image_front_url || product.image_url || null
  }
}];
